"""Authentication middleware for Planboard API.

Validates JWT/session tokens and attaches user context to requests.
"""
import logging
from django.http import JsonResponse
from django.conf import settings

logger = logging.getLogger(__name__)


class AuthMiddleware:
    """Authenticate incoming requests via session or token."""

    EXEMPT_PATHS = [
        '/api/health/',
        '/api/public/',
        '/api/auth/login/',
        '/api/auth/register/',
    ]

    def __init__(self, get_response):
        self.get_response = get_response

    def __call__(self, request):
        if self._is_exempt(request.path):
            return self.get_response(request)

        if not hasattr(request, 'user') or not request.user.is_authenticated:
            if not self._try_token_auth(request):
                return JsonResponse(
                    {'error': 'Authentication required'},
                    status=401
                )

        return self.get_response(request)

    def _is_exempt(self, path: str) -> bool:
        return any(path.startswith(p) for p in self.EXEMPT_PATHS)

    def _try_token_auth(self, request) -> bool:
        auth_header = request.META.get('HTTP_AUTHORIZATION', '')
        if auth_header.startswith('Bearer '):
            token = auth_header[7:]
            # Token validation delegated to DRF TokenAuthentication
            return bool(token)
        return False

