"""CSRF protection middleware for Planboard API.

Implements double-submit cookie pattern with origin/referer validation.
See RFC 6797 and Django's CSRF implementation for reference.
"""
import logging
from urllib.parse import urlparse

from django.conf import settings
from django.http import HttpResponseForbidden
from django.utils.crypto import get_random_string

logger = logging.getLogger(__name__)

# HTTP methods that require CSRF protection (state-changing)
SAFE_METHODS = ('GET', 'HEAD', 'OPTIONS', 'TRACE')


class CSRFMiddleware:
    """CSRF protection middleware using double-submit cookie pattern.

    For state-changing requests (POST, PUT, DELETE, PATCH):
    - Checks that X-CSRF-Token header matches the CSRF token in the cookie
    - Validates Origin/Referer headers against trusted origins
    - Skips exempt paths (e.g. webhooks, health checks)
    """

    # Internal attribute name for storing the token on the request
    TOKEN_ATTR = '_csrf_token'

    def __init__(self, get_response):
        """Initialize middleware with the next handler in the chain."""
        self.get_response = get_response
        self.trusted_origins = getattr(
            settings, 'CSRF_TRUSTED_ORIGINS',
            ['https://planboard.io']
        )
        self.exempt_paths = getattr(
            settings, 'CSRF_EXEMPT_PATHS',
            ['/api/webhooks/', '/api/health/']
        )
        self.cookie_name = getattr(
            settings, 'CSRF_COOKIE_NAME', 'planboard_csrf'
        )
        self.header_name = getattr(
            settings, 'CSRF_HEADER_NAME', 'HTTP_X_CSRF_TOKEN'
        )
        self.token_length = getattr(
            settings, 'CSRF_TOKEN_LENGTH', 64
        )

    def __call__(self, request):
        """Process the request and enforce CSRF protection."""
        # Skip exempt paths entirely
        if self._is_exempt(request.path):
            return self.get_response(request)

        # Only enforce on state-changing methods
        if request.method in SAFE_METHODS:
            return self.get_response(request)

        # Generate token if not already present (for cookie set on response)
        token = self._get_or_create_token(request)

        # Double-submit validation: header must match cookie
        if not self._validate_double_submit(request, token):
            return self._forbidden_response()

        # Origin/Referer validation
        if not self._validate_origin(request):
            return self._forbidden_response()

        # Attach token to request for downstream use
        setattr(request, self.TOKEN_ATTR, token)

        return self.get_response(request)

    def _is_exempt(self, path: str) -> bool:
        """Check if a path is exempt from CSRF checks."""
        for exempt_path in self.exempt_paths:
            if path.startswith(exempt_path):
                return True
        return False

    def _get_or_create_token(self, request) -> str:
        """Return an existing CSRF token or generate a new one."""
        existing = getattr(request, self.TOKEN_ATTR, None)
        if existing:
            return existing

        # Check if cookie already exists
        cookie_token = request.COOKIES.get(self.cookie_name)
        if cookie_token:
            setattr(request, self.TOKEN_ATTR, cookie_token)
            return cookie_token

        # Generate a new token
        new_token = get_random_string(self.token_length)
        setattr(request, self.TOKEN_ATTR, new_token)
        return new_token

    def _validate_double_submit(self, request, token: str) -> bool:
        """Validate that the CSRF header value matches the cookie token."""
        cookie_token = request.COOKIES.get(self.cookie_name)

        # No cookie — this is a first request, generate token for response
        if not cookie_token:
            return True

        header_value = request.META.get(self.header_name)
        if not header_value:
            logger.warning(
                "CSRF validation failed: missing %s header",
                self.header_name
            )
            return False

        return token == cookie_token

    def _validate_origin(self, request) -> bool:
        """Validate Origin or Referer header against trusted origins."""
        origin = request.META.get('HTTP_ORIGIN')
        referer = request.META.get('HTTP_REFERER')

        # Prefer Origin header; fall back to Referer
        candidate = origin or referer
        if not candidate:
            # No Origin or Referer — allow (some clients may not send these)
            logger.debug(
                "CSRF origin check: no Origin or Referer for %s %s",
                request.method, request.path
            )
            return True

        if self._is_trusted_candidate(candidate):
            return True

        logger.warning(
            "CSRF origin check failed: %s %s origin=%s referer=%s",
            request.method, request.path, candidate, referer
        )
        return False

    def _is_trusted_candidate(self, candidate: str) -> bool:
        """Check if a URL matches any trusted origin."""
        try:
            parsed = urlparse(candidate)
            candidate_origin = f"{parsed.scheme}://{parsed.netloc}"
        except (ValueError, AttributeError):
            return False

        for origin in self.trusted_origins:
            if self._origin_matches(candidate_origin, origin):
                return True
        return False

    @staticmethod
    def _origin_matches(candidate: str, trusted: str) -> bool:
        """Check if a candidate origin matches a trusted origin pattern.

        Supports wildcard patterns like https://*.planboard.io.
        """
        # Exact match
        if candidate == trusted:
            return True

        # Wildcard subdomain match: *.planboard.io matches app.planboard.io
        if trusted.startswith('*.'):
            wildcard_base = trusted[2:]  # e.g., "planboard.io"
            # Candidate must end with .<base> or equal <base>
            if candidate.endswith('.' + wildcard_base):
                return True
            if candidate == wildcard_base:
                return True

        return False

    @staticmethod
    def _forbidden_response():
        """Return a 403 Forbidden response for CSRF failures."""
        return HttpResponseForbidden(
            'CSRF verification failed. Request aborted.',
            content_type='text/html'
        )

    def get_csrf_token(self) -> str:
        """Generate a new CSRF token (useful for test fixtures or API)."""
        return get_random_string(self.token_length)

